mapper.select:
SELECT E.EMPLOYEE_ID AS EMPLOYEE_ID, E.EMPLOYEE_NO AS EMPLOYEE_NO, E.NAME AS NAME, E.EMAIL AS EMAIL, E.HIRE_DATE AS HIRE_DATE, E.DEPARTMENT_CODE AS DEPARTMENT_CODE, ( SELECT C.CODE_NAME FROM JPAS_TB_CMMN_CD_DTL C WHERE 1=1 AND C.GROUP_CODE = 'DEPARTMENT' AND C.CODE = E.DEPARTMENT_CODE AND C.ACTIVE_YN = 'Y' ) AS DEPARTMENT_NAME, E.POSITION_CODE AS POSITION_CODE, ( SELECT C.CODE_NAME FROM JPAS_TB_CMMN_CD_DTL C WHERE 1=1 AND C.GROUP_CODE = 'POSITION' AND C.CODE = E.POSITION_CODE AND C.ACTIVE_YN = 'Y' ) AS POSITION_NAME, E.ACTIVE_YN AS ACTIVE_YN, E.CREATED_AT AS CREATED_AT FROM JPAS_TB_EMPLOYEE E WHERE 1=1
AND E.EMPLOYEE_NO LIKE CONCAT('%', #{employeeNo}, '%')
AND E.NAME LIKE CONCAT('%', #{name}, '%')
AND E.ACTIVE_YN = #{activeYn}
AND E.HIRE_DATE = #{hireDate}
ORDER BY E.EMPLOYEE_NO
